def is_simple_power(x, n):
    # x == 1 is always a simple power (n^0 = 1)
    if x == 1:
        return True
    # n == 1: 1^k = 1 for all k, so only x == 1 works (handled above)
    if n == 1:
        return False
    # n == 0 or x <= 0: edge cases, return False
    if n == 0 or x <= 0:
        return False
    # Multiply current by n until we reach or exceed x
