def minPath(grid, k):
    n = len(grid)

    # Find the position of cell with value 1
    row1, col1 = -1, -1
    for i in range(n):
        for j in range(n):
            if grid[i][j] == 1:
                row1, col1 = i, j
                break
        if row1 != -1:
            break

    # Find the minimum neighbor value of cell with value 1
    directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]
    min_neighbor = float('inf')
    for dr, dc in directions:
        nr, nc = row1 + dr, col1 + dc
        if 0 <= nr < n and 0 <= nc < n:
            min_neighbor = min(min_neighbor, grid[nr][nc])

    # Build the result: alternate between 1 and min_neighbor for k steps
    result = []
    for i in range(k):
        if i % 2 == 0:
            result.append(1)
        else:
            result.append(min_neighbor)

    return result

def tri(n):
    if n == 0:
        return [1]

    result = [1, 3]

    for i in range(2, n + 1):
        if i % 2 == 0:
            result.append(1 + i // 2)
        else:
            # i is odd, so i+1 is even: tri(i+1) = 1 + (i+1)/2
            tri_next = 1 + (i + 1) // 2
            result.append(result[i - 1] + result[i - 2] + tri_next)

    return result

