def is_nested(string):
    depth = 0
    max_depth = 0
    for ch in string:
        if ch == '[':
            depth += 1
            if depth > max_depth:
                max_depth = depth
        elif ch == ']':
            if depth > 0:
                depth -= 1
    return max_depth >= 2

